# Allow confined caddy (httpd_t) to talk to tailscaled's localapi unix
# socket (/var/run/tailscale/tailscaled.sock, labeled var_run_t; tailscaled
# itself runs as unconfined_service_t). Needed for ts.net cert fetching —
# without it every TLS handshake logs "connect: permission denied".
module caddy-tailscale 1.0;

require {
    type httpd_t;
    type var_run_t;
    type unconfined_service_t;
    class sock_file write;
    class unix_stream_socket connectto;
}

allow httpd_t var_run_t:sock_file write;
allow httpd_t unconfined_service_t:unix_stream_socket connectto;

